// "name" adlı dəyişən yaradıram
const name = "Aysel";
console.log(name); // nəticə: Aysel

// Dəyəri dəyişməyə cəhd edirəm
// name = "Kamran"; // Xəta: Assignment to constant variable

// Blok scope nümunəsi
if (true) {
  const color = "blue";
  console.log(color); // nəticə: blue
}
// console.log(color); // Xəta: color is not defined, çünki blok xaricində işləmir

// Hoisting nümunəsi
// console.log(toy); // Xəta: Cannot access "toy" before initialization
const toy = "robot";
console.log(toy); // nəticə: robot

// Obyekt ilə nümunə
const settings = { theme: "dark" };
settings.theme = "light"; // Bu işləyir, çünki obyektin içindəki dəyər dəyişir
console.log(settings.theme); // nəticə: light
// settings = { theme: "blue" }; // Xəta: Assignment to constant variable

// const ilə təkrar elan etmək olmaz
const gadget = "phone";
// const gadget = "earphones"; // Xəta: gadget has already been declared

// Dəyəri dəyişmək də olmaz
// gadget = "earphones"; // Xəta: Assignment to constant variable

// let ilə dəyəri dəyişə bilərsən
let drink = "cola";
drink = "water";
console.log(drink); // nəticə: water

