// Create a variable called "name"
const name = "Aysel";
console.log(name); // Output: Aysel

// Try to change the value
// name = "Kamran"; // Error: Assignment to constant variable

// Block scope example
if (true) {
  const color = "blue";
  console.log(color); // Output: blue
}
// console.log(color); // Error: color is not defined, because it doesn’t exist outside the block

// Hoisting example
// console.log(toy); // Error: Cannot access "toy" before initialization
const toy = "robot";
console.log(toy); // Output: robot

// Object example
const settings = { theme: "dark" };
settings.theme = "light"; // This works because the object’s property is changed
console.log(settings.theme); // Output: light
// settings = { theme: "blue" }; // Error: Assignment to constant variable

// Redeclaring with const is not allowed
const gadget = "phone";
// const gadget = "earphones"; // Error: gadget has already been declared

// Reassigning is also not allowed
// gadget = "earphones"; // Error: Assignment to constant variable

// You can change the value with let
let drink = "cola";
drink = "water";
console.log(drink); // Output: water

