// Создаём переменную под названием "name"
const name = "Айсель";
console.log(name); // Вывод: Айсель

// Пытаемся изменить значение
// name = "Кямран"; // Ошибка: Assignment to constant variable

// Пример блочной области видимости
if (true) {
  const color = "синий";
  console.log(color); // Вывод: синий
}
// console.log(color); // Ошибка: color не определён, так как не существует вне блока

// Пример hoisting
// console.log(toy); // Ошибка: Cannot access "toy" before initialization
const toy = "робот";
console.log(toy); // Вывод: робот

// Пример с объектом
const settings = { theme: "тёмная" };
settings.theme = "светлая"; // Это работает, так как изменяется свойство объекта
console.log(settings.theme); // Вывод: светлая
// settings = { theme: "синяя" }; // Ошибка: Assignment to constant variable

// Повторное объявление с const не допускается
const gadget = "телефон";
// const gadget = "наушники"; // Ошибка: gadget уже объявлена

// Переназначение тоже не допускается
// gadget = "наушники"; // Ошибка: Assignment to constant variable

// С let можно изменить значение
let drink = "кола";
drink = "вода";
console.log(drink); // Вывод: вода

